__kernel void compute_distances(__global const char *sandbox, __global float *z, 
                                const float target_lat, const float target_long, 
                                const int rec_count) {
    int i = get_global_id(0);
    if (i < rec_count) {
        int base_idx = i * 49 + 27; // LATITUDE_POS - 1 = 28 - 1 = 27
        // Extract latitude string (6 chars to include possible space or null)
        char lat_str[7];
        for (int c = 0; c < 6; c++) {
            lat_str[c] = sandbox[base_idx + c];
        }
        lat_str[6] = '\0';

        // Extract longitude string (6 chars)
        char long_str[7];
        for (int c = 0; c < 6; c++) {
            long_str[c] = sandbox[base_idx + 6 + c];
        }
        long_str[6] = '\0';

        // Convert to float
        float tmp_lat = 0.0f;
        float tmp_long = 0.0f;

        // Simple atof implementation for fixed length strings
        // Note: This assumes the format is consistent and valid
        // For latitude
        {
            int sign = 1;
            int idx = 0;
            if (lat_str[0] == '-') {
                sign = -1;
                idx = 1;
            }
            float val = 0.0f;
            int decimal_seen = 0;
            float decimal_factor = 0.1f;
            for (; lat_str[idx] != '\0' && lat_str[idx] != ' '; idx++) {
                char ch = lat_str[idx];
                if (ch == '.') {
                    decimal_seen = 1;
                } else if (ch >= '0' && ch <= '9') {
                    if (!decimal_seen) {
                        val = val * 10.0f + (ch - '0');
                    } else {
                        val = val + (ch - '0') * decimal_factor;
                        decimal_factor *= 0.1f;
                    }
                }
            }
            tmp_lat = sign * val;
        }
        // For longitude
        {
            int sign = 1;
            int idx = 0;
            if (long_str[0] == '-') {
                sign = -1;
                idx = 1;
            }
            float val = 0.0f;
            int decimal_seen = 0;
            float decimal_factor = 0.1f;
            for (; long_str[idx] != '\0' && long_str[idx] != ' '; idx++) {
                char ch = long_str[idx];
                if (ch == '.') {
                    decimal_seen = 1;
                } else if (ch >= '0' && ch <= '9') {
                    if (!decimal_seen) {
                        val = val * 10.0f + (ch - '0');
                    } else {
                        val = val + (ch - '0') * decimal_factor;
                        decimal_factor *= 0.1f;
                    }
                }
            }
            tmp_long = sign * val;
        }

        float diff_lat = tmp_lat - target_lat;
        float diff_long = tmp_long - target_long;
        z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
    }
}
